#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX 100005

struct Tree {
    double height;
    double rate;
    double time;
};

int compare(const void *a, const void *b) {
    struct Tree *tree1 = (struct Tree *)a;
    struct Tree *tree2 = (struct Tree *)b;
    if (tree1->time < tree2->time) return -1;
    else if (tree1->time > tree2->time) return 1;
    else return 0;
}

int main() {
    int N, i;
    double W, L;
    scanf("%d %lf %lf", &N, &W, &L);
    struct Tree trees[N];
    for (i = 0; i < N; i++) {
        scanf("%lf %lf", &trees[i].height, &trees[i].rate);
        if (trees[i].height >= L) trees[i].time = 0;
        else trees[i].time = (L - trees[i].height) / trees[i].rate;
    }
    qsort(trees, N, sizeof(struct Tree), compare);
    double totalWood = 0;
    double time = 0;
    for (i = 0; i < N; i++) {
        if (time < trees[i].time) time = trees[i].time;
        totalWood += trees[i].height + trees[i].rate * time;
        if (totalWood >= W) break;
    }
    printf("%.0lf\n", time);
    return 0;
}

