code.Java:
import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Tree implements Comparable<Tree> {
        double height;
        double rate;
        double time;

        public Tree(double height, double rate) {
            this.height = height;
            this.rate = rate;
        }

        @Override
        public int compareTo(Tree o) {
            return Double.compare(this.time, o.time);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        double W = scanner.nextDouble();
        double L = scanner.nextDouble();
        Tree[] trees = new Tree[N];
        for (int i = 0; i < N; i++) {
            double height = scanner.nextDouble();
            double rate = scanner.nextDouble();
            trees[i] = new Tree(height, rate);
            if (height >= L) trees[i].time = 0;
            else trees[i].time = (L - height) / rate;
        }
        Arrays.sort(trees);
        double totalWood = 0;
        double time = 0;
        for (int i = 0; i < N; i++) {
            if (time < trees[i].time) time = trees[i].time;
            totalWood += trees[i].height + trees[i].rate * time;
            if (totalWood >= W) break;
        }
        System.out.println((int)time);
    }
}

