const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function readLine() {
    return input[idx++];
}

function readNumber() {
    return parseFloat(readLine());
}

function readArray() {
    return readLine().split(' ').map(Number);
}

class Tree {
    constructor(height, rate) {
        this.height = height;
        this.rate = rate;
        this.time = 0;
    }
}

let N, W, L;
[N, W, L] = readArray();
N = parseInt(N);
let trees = [];
for (let i = 0; i < N; i++) {
    let [height, rate] = readArray();
    let tree = new Tree(height, rate);
    if (height >= L) tree.time = 0;
    else tree.time = (L - height) / rate;
    trees.push(tree);
}
trees.sort((a, b) => a.time - b.time);
let totalWood = 0;
let time = 0;
for (let tree of trees) {
    if (time < tree.time) time = tree.time;
    totalWood += tree.height + tree.rate * time;
    if (totalWood >= W) break;
}
